export const TitleOverlapFacilitator = styled.span`
  /*
    We need to allow for the text to overspill the boundary of the title
    otherwise the truncation ellipsis is clipped as it is not considered when
    calculating the width of the wrapper. If padding is used then overflowing
    text is visible.
  */
  display: block;
  padding: var(--spacing) var(--padding-x) 0 0;
  margin: 0 calc(var(--padding-x) * -1) var(--spacing) 0;

  ${clampLines('--lines', '--line-height')}
`;
