import { FC } from 'react';

import Checkbox from '#components/Checkbox';
import LoadingEllipsis from '#components/LoadingEllipsis';
import { MAX_SELECTED_ITEMS } from '#components/ProductComparison/ControlBar/ControlBar.constants';

import {
  BUY_NOW_LABEL,
  UNAVAILABLE_LABEL,
} from './ProductCarouselCard.constants';
import {
  BestFor,
  BuyButton,
  ContentWrapper,
  SelectProduct,
  Image,
  Price,
  ReviewButton,
  Rating,
  Title,
  TitleOverlapFacilitator,
  Wrapper,
  BuyButtonContainer,
} from './ProductCarouselCard.styles';
import { ProductCarouselCardProps } from './ProductCarouselCard.types';

const ProductCarouselCard: FC<ProductCarouselCardProps> = ({
  product: {
    id,
    anchorHref,
    bestForPrefixed,
    image,
    title,
    rating,
    isAvailable,
  },
  isComparison,
  isLoading = false,
  price,
  vendorLink,
  selectedItemIDs,
  toggleSelectedProduct,
}) => {
  const isDisabled =
    !selectedItemIDs.includes(id) &&
    selectedItemIDs.length >= MAX_SELECTED_ITEMS;

  return (
    <Wrapper>
      <Image>{image}</Image>
      <ContentWrapper>
        <BestFor href={anchorHref}>{bestForPrefixed}</BestFor>
        <Rating value={rating} />
        <Title>
          <TitleOverlapFacilitator>{title}</TitleOverlapFacilitator>
        </Title>
        <ReviewButton href={anchorHref}>Read review</ReviewButton>
        <Price>
          {isLoading ? <LoadingEllipsis /> : <strong>{price}</strong>}
        </Price>
        <BuyButtonContainer>
          <BuyButton
            href={vendorLink}
            target="_blank"
            rel="noreferrer"
            disabled={!isAvailable}
            isExternal={true}
          >
            {isAvailable ? BUY_NOW_LABEL : UNAVAILABLE_LABEL}
          </BuyButton>
        </BuyButtonContainer>

        {isComparison && (
          <SelectProduct>
            <Checkbox
              id={id}
              onChange={() => {
                toggleSelectedProduct(id);
              }}
              checked={selectedItemIDs.includes(id)}
              disabled={isDisabled}
            >
              Compare
            </Checkbox>
          </SelectProduct>
        )}
      </ContentWrapper>
    </Wrapper>
  );
};

export default ProductCarouselCard;
